    function insT(p, blocks, warnItems) { var ti = partSeq.indexOf(p); if (ti < 0 || !THEORY[ti] || !THEORY[ti].blocks) return; var bl = THEORY[ti].blocks; if (blocks && blocks.length) { var wi = -1; for (var i = 0; i < bl.length; i++) if (bl[i].k === "note" && bl[i].v === "warn") wi = i; bl.splice.apply(bl, [(wi < 0 ? bl.length : wi), 0].concat(blocks)); } if (warnItems && warnItems.length) { var w = null; for (var j2 = 0; j2 < bl.length; j2++) if (bl[j2].k === "note" && bl[j2].v === "warn") w = bl[j2]; if (w && w.list) Array.prototype.push.apply(w.list, warnItems); } }
    var ADDS = [{"p":"PART 3. 납세의무자·납세지·납세의무 성립","q":[{"answer":"O","text":"제조자는 제조장으로부터 반출한 담배에 대하여 담배소비세를 납부할 의무가 있다.","exp":"옳다. 제조자는 제조장에서 반출한 담배에 대해 납세의무를 진다 — 기본 납세의무자 3유형 중 하나다. 수입판매업자는 보세구역 반출, 반입자는 입국 반입 담배 기준으로 각각 납세의무를 진다.","src":"2025 지방직 9급"}],"tb":[],"wi":[]},{"p":"PART 2. 과세대상·과세표준·세율","q":[{"answer":"X","text":"담배소비세의 세율은 그 세율의 100분의 50의 범위에서 조례로 가감할 수 있다.","exp":"담배소비세는 일정세율이라 조례로 가감할 수 없다. 100분의 50 조례 가감은 취득세·재산세 등 표준세율 세목에 적용되고, 담배소비세는 대통령령으로 100분의 30 범위에서만 가감한다. ‘조례로 100분의 50 가감’이 틀렸다.","src":"2025 지방직 9급"},{"answer":"O","text":"표준세율은 조례로 100분의 50의 범위에서 가감할 수 있지만, 담배소비세는 일정세율이어서 대통령령으로 100분의 30의 범위에서만 가감할 수 있다.","exp":"옳다. 조례 50% 가감은 표준세율의 몫이고, 담배소비세는 일정세율이라 대통령령 30% 가감만 가능하다. 가감 범위(50 vs 30)와 주체(조례 vs 대통령령)가 둘 다 다르다는 점이 핵심이다."}],"tb":[{"k":"sub","t":"⚠️ 조례 100분의 50 가감은 담배소비세에 없다"},{"k":"p","t":"담배소비세는 일정세율이라 지방자치단체가 조례로 세율을 가감할 수 없다. ‘100분의 50의 범위에서 조례로 가감’은 취득세·재산세 등 표준세율 세목에 적용되는 규칙이고, 담배소비세에 허용되는 조정은 대통령령에 의한 100분의 30 범위의 탄력세율뿐이다. 가감 수치(50↔30)와 주체(조례↔대통령령)를 모두 바꿔야 옳은 문장이 된다."}],"wi":["담배소비세 세율 = 조례로 100분의 50 가감 ❌ → 조례 가감 불가, 대통령령으로 100분의 30만 ⭕"]},{"p":"PART 4. 미납세반출·반출의제·과세면제·세액공제환급","q":[{"answer":"O","text":"담배를 다른 담배의 원료로 사용하기 위하여 반출하는 것에 대하여는 담배소비세를 징수하지 아니한다.","exp":"옳다. 원료용 반출은 미납세반출이라 이 단계에서는 징수하지 않고, 그 원료로 만든 담배가 반출될 때 과세한다. 다만 미납세반출은 면제와 달리 사유가 소멸하면 과세될 수 있는 조건부 유보다.","src":"2025 지방직 9급"},{"answer":"O","text":"수입판매업자가 담배를 외항선의 선원에 대한 판매에 제공하는 경우에는 담배소비세를 면제한다.","exp":"옳다. 외항선(외국을 오가는 선박)의 선원에 대한 판매는 실질적으로 국외에서 소비되므로 면제된다. 국제항로 항공기·여객선 승객 판매, 원양어선 선원 판매와 같은 ‘해외 소비’ 계열의 면제 사유다.","src":"2025 지방직 9급"},{"answer":"X","text":"수입판매업자가 담배를 국내 항로만 운항하는 여객선의 선원에 대한 판매에 제공하는 경우에는 담배소비세를 면제한다.","exp":"국내 항로만 운항하는 여객선 선원에 대한 판매는 국내 소비이므로 면제 대상이 아니다. 면제되는 것은 외항선·국제항로 선박의 선원·승객에 대한 판매 등 실질적으로 해외에서 소비되는 경우다. ‘국내 항로 여객선’이 틀렸다."}],"tb":[{"k":"sub","t":"🚢 외항선 선원 판매도 ‘해외 소비’ 면제"},{"k":"p","t":"외항선(외국을 오가는 선박)의 선원에게 판매하는 담배는 국제항로 항공기·여객선 승객 판매, 원양어선 선원 판매와 함께 실질적으로 국외에서 소비되는 ‘해외 소비’ 계열의 면제 사유다. 반면 국내 항로만 운항하는 선박·항공기에서의 판매는 국내 소비이므로 면제되지 않는다."}],"wi":["외항선 선원에 대한 판매 = 과세 ❌ → 면제(해외 소비 계열) ⭕"]}];
    for (var ai = 0; ai < ADDS.length; ai++) { insQ(ADDS[ai].p, ADDS[ai].q); insT(ADDS[ai].p, ADDS[ai].tb, ADDS[ai].wi); }
